arguments.command:
# Check what's at those addresses - might be in a section without debug info
DBG="/tmp/libmonosgen-2.0.so.dbg"
aarch64-linux-gnu-nm -C "$DBG" 2>/dev/null | awk '{print $1, $2, $3}' | sort | awk -v addr="002f4b20" '
$1 <= addr { prev=$0 }
$1 > addr { print "Before:", prev; print "After:", $0; exit }
'
